const body = $input.item.json.body;
const tipo = body.tipo || 'text';
const mensaje = body.mensaje || '';
const telefono = body.telefono;
const mediaUrl = body.mediaUrl;
const fileName = body.fileName || 'archivo';

let cleanedPhone = String(telefono).replace(/\D/g, '');
if (cleanedPhone.startsWith('521') && cleanedPhone.length === 13) {
  cleanedPhone = '52' + cleanedPhone.substring(3);
}

let payload = {
  messaging_product: 'whatsapp',
  to: cleanedPhone,
  type: tipo === 'plantilla' ? 'template' : tipo
};

if (tipo === 'text') {
  payload.text = { body: mensaje };
} else if (tipo === 'template' || tipo === 'plantilla') {
  payload.template = {
    name: body.plantilla || 'inicio_conversacion',
    language: {
      code: body.idioma || 'es_MX'
    }
  };
} else if (tipo === 'image') {
  payload.image = { link: mediaUrl };
  if (mensaje) payload.image.caption = mensaje;
} else if (tipo === 'audio') {
  payload.audio = { link: mediaUrl };
} else if (tipo === 'video') {
  payload.video = { link: mediaUrl };
  if (mensaje) payload.video.caption = mensaje;
} else if (tipo === 'document') {
  payload.document = { link: mediaUrl, filename: fileName };
  if (mensaje) payload.document.caption = mensaje;
}

$input.item.json.fbPayload = payload;
return $input.item;
